import{_ as i,c as t,a as s,o as a}from"./app-CEcM0piI.js";const d={};function n(r,e){return a(),t("div",null,e[0]||(e[0]=[s('<h2 id="定位组成" tabindex="-1"><a class="header-anchor" href="#定位组成"><span>定位组成</span></a></h2><p>定位：将盒子定在某一个位置，所以定位也是在摆放盒子，按照定位的方式移动盒子。 定位=定位模式+边偏移。 定位模式用于指定一个元素在文档中的定位方式。边偏移则决定了该元素的最终位置。</p><h3 id="边偏移" tabindex="-1"><a class="header-anchor" href="#边偏移"><span>边偏移</span></a></h3><p>边偏移就是定位的盒子移动到最终位置。有 top、bottom、left和right 4 个属性。</p><table><thead><tr><th>边偏移属性</th><th>示例</th><th>描述</th></tr></thead><tbody><tr><td>top</td><td>top:80px</td><td>顶端偏移量，定义元素相对于其父元素上边线的距离。</td></tr><tr><td>bottom</td><td>bottom:80px</td><td>底部偏移量，定义元素相对于其父元素下边线的距离。</td></tr><tr><td>left</td><td>left:80px</td><td>左侧偏移量，定义元素相对于其父元素左边线的距离。</td></tr><tr><td>right</td><td>right:80px</td><td>右侧偏移量，定义元素相对于其父元素右边线的距离</td></tr></tbody></table><h3 id="定位模式" tabindex="-1"><a class="header-anchor" href="#定位模式"><span>定位模式</span></a></h3><p>通过CSS的position属性来设置</p><table><thead><tr><th>值</th><th>语义</th></tr></thead><tbody><tr><td>static</td><td>静态定位</td></tr><tr><td>relative</td><td>相对定位</td></tr><tr><td>absolute</td><td>绝对定位</td></tr><tr><td>fixed</td><td>固定定位</td></tr></tbody></table><h4 id="静态定位" tabindex="-1"><a class="header-anchor" href="#静态定位"><span>静态定位</span></a></h4><p>静态定位是元素的默认定位方式，无定位的意思</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>选择器{position:static;}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>静态定位按照标准流特性摆放位置，它没有边偏移</p><h4 id="相对定位" tabindex="-1"><a class="header-anchor" href="#相对定位"><span>相对定位</span></a></h4><p>相对定位是元素在移动位置的时候，是相对于它原来的位置来说的</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>选择器{position:relative;}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ol><li>它是相对于自己原来的位置来移动的（移动位置的时候参照点是自己原来的位置）。</li><li>原来在标准流的位置继续占有，后面的盒子仍然以标准流的方式对待它。（不脱标，继续保留原来位置）</li></ol><h4 id="绝对定位" tabindex="-1"><a class="header-anchor" href="#绝对定位"><span>绝对定位</span></a></h4><p>绝对定位是元素在移动位置的时候，是相对于它祖先元素来说的</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>选择器position: absolute;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ol><li>如果没有祖先元素或者祖先元素没有定位，则以浏览器为准定位（Document文档）</li><li>如果祖先元素有定位（相对、绝对、固定定位），则以最近一级的有定位祖先元素为参考点移动位置。</li></ol><h4 id="固定定位" tabindex="-1"><a class="header-anchor" href="#固定定位"><span>固定定位</span></a></h4><p>固定定位是元素固定于浏览器可视区的位置。主要使用场景：可以在浏览器页面滚动时元素的位置不会改变。</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>选择器{position: fixed;}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ol><li>以浏览器的可视窗口为参照点移动元素 跟父元素没有任何关系 不随滚动条滚动</li><li>固定定位不在占有原先的位置 固定定位也是脱标的，其实固定定位也可以看做是一种特殊的绝对定位</li></ol><h5 id="附着版心" tabindex="-1"><a class="header-anchor" href="#附着版心"><span>附着版心</span></a></h5><p>普通的固定定位只会显示在窗口固定的位置</p><p>也可以将固定定位固定在版心旁边,当版心缩放时它也紧挨着版心缩放</p><ol><li>让固定定位的盒子let:50%.走到浏览器可视区（也可以看做版心）的一半位置。</li><li>让固定定位的盒子margin-left:版心宽度的一半距离。多走版心宽度的一半位置 就可以让固定定位的盒子贴着版心右侧对齐了。</li></ol><h4 id="粘性定位" tabindex="-1"><a class="header-anchor" href="#粘性定位"><span>粘性定位</span></a></h4><p>粘性定位可以被认为是相对定位和固定定位的混合。Sticky粘性的</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>选择器{position:sticky;top:10px;}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ol><li>以浏览器的可视窗口为参照点移动元素（固定定位特点）</li><li>粘性定位占有原先的位置（相对定位特点）</li><li>必须添加top、left、right、bottom其中一个才有效 跟页面滚动搭配使用。兼容性较差，IE不支持。一般使用js实现</li></ol><h3 id="定位叠放次序" tabindex="-1"><a class="header-anchor" href="#定位叠放次序"><span>定位叠放次序</span></a></h3><p>在使用定位布局时，可能会出现盒子重叠的情况。此时，可以使用z-index来控制盒子的前后次序（z轴）</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>选择器{z-index:1;}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>数值可以是正整数、负整数或0，默认是auto，数值越大，盒子越靠上 如果属性值相同，则按照书写顺序，后来居上 数字后面不能加单位 只有定位的盒子才有z-index属性</p><h2 id="浮动和定位的拓展" tabindex="-1"><a class="header-anchor" href="#浮动和定位的拓展"><span>浮动和定位的拓展</span></a></h2><p>绝对定位（固定定位）会完全压住盒子 浮动元素不同，只会压住它下面标准流的盒子，但是不会压住下面标准流盒子里面的文字（图片）</p><p>但是绝对定位（固定定位）会压住下面标准流所有的内容。</p><p>因为浮动最开始是做文字环绕效果的</p>',40)]))}const h=i(d,[["render",n]]),p=JSON.parse('{"path":"/front/css/6/","title":"6 定位","lang":"zh-CN","frontmatter":{"title":"6 定位","createTime":"2025/06/18 21:06:02","permalink":"/front/css/6/"},"readingTime":{"minutes":3.83,"words":1149},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/前端/CSS/6 定位.md","headers":[]}');export{h as comp,p as data};
